import{c as h,S as t,j as a,m as i}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Khung chương trình","description":"","frontmatter":{},"headers":[],"relativePath":"admin/khung-chuong-trinh.md","filePath":"admin/khung-chuong-trinh.md","lastUpdated":0}'),r={name:"admin/khung-chuong-trinh.md"};function o(g,n,c,s,l,u){return t(),a("div",null,[...n[0]||(n[0]=[i(`<h1 id="khung-chuong-trinh" tabindex="-1">Khung chương trình <a class="header-anchor" href="#khung-chuong-trinh" aria-label="Permalink to “Khung chương trình”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/thematic/program</code></p><p><strong>Khung chương trình</strong> (Program) là tầng phân loại cao nhất của hệ thống đào tạo. Mỗi khóa học phải thuộc một khung chương trình.</p><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><p>Khung chương trình tương ứng với <strong>một định hướng học</strong> lớn, ví dụ:</p><ul><li>&quot;Luyện thi ĐGNL HSA 2026&quot;</li><li>&quot;Luyện thi ĐGTD Bách Khoa 2026&quot;</li><li>&quot;Tốt nghiệp THPT 2026 - Khối A&quot;</li><li>&quot;Học liệu giáo trình lớp 12&quot;</li><li>&quot;Kiểm tra đầu vào toàn trường&quot;</li></ul><p>Một khung chương trình có thể chứa <strong>nhiều khóa học</strong> (cùng chủ đề nhưng khác cấp độ, khác giáo viên).</p><h2 id="thuoc-tinh" tabindex="-1">Thuộc tính <a class="header-anchor" href="#thuoc-tinh" aria-label="Permalink to “Thuộc tính”">​</a></h2><table tabindex="0"><thead><tr><th>Trường</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tên khung</strong></td><td>Tên hiển thị (vd &quot;Luyện thi ĐGNL 2026&quot;)</td></tr><tr><td><strong>Mã khung</strong></td><td>Mã duy nhất dùng cho URL &amp; báo cáo</td></tr><tr><td><strong>Loại chương trình</strong></td><td>Một trong 8 loại: Kiểm tra đầu vào / Thi thử ĐGNL / Thi thử ĐGTD / Thi TNTHPT / Luyện thi ĐGNL-ĐGTD / Ôn thi THCS-THPT / Học liệu / Bộ đề</td></tr><tr><td><strong>Ảnh bìa</strong></td><td>Hiển thị ở trang chủ và trang khóa học</td></tr><tr><td><strong>Mô tả ngắn</strong></td><td>Dùng cho SEO và preview</td></tr><tr><td><strong>Mô tả chi tiết</strong></td><td>Rich text (có hình, video) cho trang chi tiết</td></tr><tr><td><strong>Trạng thái</strong></td><td>Công khai / Ẩn</td></tr><tr><td><strong>Thứ tự hiển thị</strong></td><td>Số thứ tự trên trang chủ</td></tr></tbody></table><h2 id="tao-khung-chuong-trinh" tabindex="-1">Tạo khung chương trình <a class="header-anchor" href="#tao-khung-chuong-trinh" aria-label="Permalink to “Tạo khung chương trình”">​</a></h2><ol><li>Bấm <strong>Thêm khung chương trình</strong>.</li><li>Nhập đầy đủ thông tin (xem bảng trên).</li><li><strong>Chọn loại chương trình</strong> - đây là quyết định quan trọng vì ảnh hưởng đến: <ul><li>Loại đề thi sử dụng (đề ĐGNL khác đề ĐGTD).</li><li>Cách hiển thị kết quả thi.</li><li>Cách học viên truy cập từ trang chủ.</li></ul></li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="sua-khung-chuong-trinh" tabindex="-1">Sửa khung chương trình <a class="header-anchor" href="#sua-khung-chuong-trinh" aria-label="Permalink to “Sửa khung chương trình”">​</a></h2><ul><li>Có thể đổi tên, ảnh, mô tả bất cứ lúc nào.</li><li><strong>Không nên đổi &quot;Loại chương trình&quot;</strong> sau khi đã có khóa học và học viên - sẽ gây sai lệch loại đề thi sử dụng.</li></ul><h2 id="an-xoa-khung" tabindex="-1">Ẩn / Xóa khung <a class="header-anchor" href="#an-xoa-khung" aria-label="Permalink to “Ẩn / Xóa khung”">​</a></h2><ul><li><strong>Ẩn</strong>: gắn cờ &quot;Đã ẩn&quot; → không hiển thị trên trang chủ, nhưng học viên đã mua khóa thuộc khung vẫn vào học được.</li><li><strong>Xóa</strong>: chỉ xóa được khi <strong>không còn khóa học</strong> nào nằm trong khung.</li></ul><h2 id="quan-he-voi-cac-phan-khac" tabindex="-1">Quan hệ với các phần khác <a class="header-anchor" href="#quan-he-voi-cac-phan-khac" aria-label="Permalink to “Quan hệ với các phần khác”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Khung chương trình</span></span>
<span class="line"><span>  └── Khóa học (mua từ đây)</span></span>
<span class="line"><span>        └── Chương học</span></span>
<span class="line"><span>              └── Chuyên đề</span></span>
<span class="line"><span>                    └── Bài giảng</span></span>
<span class="line"><span>                    └── Đề kiểm tra cuối chuyên đề</span></span></code></pre></div><p>→ Bước tiếp: tạo <a href="./khoa-hoc">Khóa học</a> trong khung.</p><h2 id="thuc-hanh-chuan" tabindex="-1">Thực hành chuẩn <a class="header-anchor" href="#thuc-hanh-chuan" aria-label="Permalink to “Thực hành chuẩn”">​</a></h2><ul><li>Đặt tên khung <strong>có năm thi</strong> (vd &quot;ĐGNL 2026&quot;) để học sinh các năm sau không bị lẫn.</li><li>Khi sang năm mới, <strong>clone khung cũ</strong> thay vì tạo mới hoàn toàn (nếu hệ thống có nút clone), để tiết kiệm thời gian nhập liệu.</li><li><strong>Ảnh bìa</strong> nên đồng nhất kích thước (ví dụ 1200×630) để trang chủ hiển thị đẹp.</li></ul>`,20)])])}const k=h(r,[["render",o]]);export{d as __pageData,k as default};
